<section class="bg-[var(--color-bg)]">
    <div class="mx-auto w-[92%] sm:w-[90%] md:w-[88%] lg:w-[85%] py-12 md:py-16">
        <h1 class="text-3xl md:text-4xl font-extrabold tracking-tight text-[var(--color-text)]">Priority Support</h1>
        <p class="mt-3 text-[var(--color-muted)] max-w-2xl">Dedicated support for our business partners and high-volume customers. Get faster responses and a direct line to our experts.</p>

        <div class="mt-10 grid gap-6 md:grid-cols-3">
            <div class="rounded-[var(--radius-card)] border border-[var(--color-border)] bg-[var(--color-surface)] p-6 text-center">
                <div class="mx-auto w-12 h-12 rounded-xl bg-[var(--color-accent)]/10 flex items-center justify-center text-[var(--color-accent)] mb-4">
                    <svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><circle cx="12" cy="12" r="10"/><polyline points="12 6 12 12 16 14"/></svg>
                </div>
                <h3 class="text-base font-semibold text-[var(--color-text)]">Fast Response</h3>
                <p class="mt-2 text-sm text-[var(--color-muted)]">Priority queue with under 2-hour response during business hours.</p>
            </div>
            <div class="rounded-[var(--radius-card)] border border-[var(--color-border)] bg-[var(--color-surface)] p-6 text-center">
                <div class="mx-auto w-12 h-12 rounded-xl bg-[var(--color-accent)]/10 flex items-center justify-center text-[var(--color-accent)] mb-4">
                    <svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><path d="M22 16.92v3a2 2 0 0 1-2.18 2 19.79 19.79 0 0 1-8.63-3.07A19.5 19.5 0 0 1 4.69 12 19.79 19.79 0 0 1 1.61 3.18 2 2 0 0 1 3.6 1h3a2 2 0 0 1 2 1.72"/></svg>
                </div>
                <h3 class="text-base font-semibold text-[var(--color-text)]">Direct Line</h3>
                <p class="mt-2 text-sm text-[var(--color-muted)]">Dedicated phone and email for priority-tier partners.</p>
            </div>
            <div class="rounded-[var(--radius-card)] border border-[var(--color-border)] bg-[var(--color-surface)] p-6 text-center">
                <div class="mx-auto w-12 h-12 rounded-xl bg-[var(--color-accent)]/10 flex items-center justify-center text-[var(--color-accent)] mb-4">
                    <svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><path d="M17 21v-2a4 4 0 0 0-4-4H5a4 4 0 0 0-4 4v2"/><circle cx="9" cy="7" r="4"/><path d="M23 21v-2a4 4 0 0 0-3-3.87"/><path d="M16 3.13a4 4 0 0 1 0 7.75"/></svg>
                </div>
                <h3 class="text-base font-semibold text-[var(--color-text)]">Account Manager</h3>
                <p class="mt-2 text-sm text-[var(--color-muted)]">A named contact who knows your business and order history.</p>
            </div>
        </div>

        <div class="mt-10 rounded-[var(--radius-card)] border border-[var(--color-border)] bg-[var(--color-surface)] p-6">
            <h2 class="text-lg font-bold text-[var(--color-text)] mb-2">How to qualify</h2>
            <p class="text-sm text-[var(--color-muted)]">Priority Support is available to all wholesale partners, authorized dealers, and customers with annual spend above $5,000. <a href="/b2b-contact" class="text-[var(--color-accent)] hover:underline">Contact our B2B team</a> to learn more.</p>
        </div>
    </div>
</section>
